window.bookSummaryJSON = "<p>All five audiobooks in the best-selling <i>Limitless Lands</i> series are now together in one collection! <br> <br> Colonel James Raytak is about to die.<br> <br> The 93-year-old combat veteran is living his last days in a nursing home, and his only hope for survival is found inside the virtual world of Limitless Lands.<br> <br> With every swing of his sword and every command given to his army, Raytak is one step closer to returning to the people he loves. Many foes will stand in his path, and despite a lifetime of military experience and powerful allies, victory is not assured.</p>"; 
